const tabs = Array.from(document.querySelectorAll('[role="tab"]'));
const panels = Array.from(document.querySelectorAll('[role="tabpanel"]'));

let activeIndex = 0;

function selectTab(index) {
  activeIndex = index;
  tabs.forEach((tab, idx) => {
    const isSelected = idx === index;
    tab.setAttribute('aria-selected', isSelected.toString());
    tab.setAttribute('tabindex', isSelected ? '0' : '-1');
    tab.className = isSelected 
      ? 'flex-1 py-2 font-bold text-center border-b-2 border-indigo-500 focus:outline-none'
      : 'flex-1 py-2 font-semibold text-slate-400 text-center border-b-2 border-transparent focus:outline-none';
    if (isSelected) tab.focus();
  });

  panels.forEach((panel, idx) => {
    panel.classList.toggle('hidden', idx !== index);
  });
}

tabs.forEach((tab, index) => {
  tab.addEventListener('click', () => selectTab(index));

  tab.addEventListener('keydown', (e) => {
    if (e.key === 'ArrowRight') {
      const nextIdx = (index + 1) % tabs.length;
      selectTab(nextIdx);
    } else if (e.key === 'ArrowLeft') {
      const prevIdx = (index - 1 + tabs.length) % tabs.length;
      selectTab(prevIdx);
    }
  });
});
